      Symbol.bindElementAction(compId, symbolName, "${_Sag_Ok_002}", "click", function(sym, e) {
         var myKombinPanelsCount = sym.getVariable("kombinPanelsCount");
         
         if(myKombinPanelsCount < 1)
         {
         	myKombinPanelsCount++;
         	sym.setVariable("kombinPanelsCount", myKombinPanelsCount);
         
         	if(myKombinPanelsCount == 1)
         	{
         		sym.$("kombinPanels").css('clip','rect(0px,730px,240px,130px)');
         		sym.$("kombinPanels").css({"position":"absolute", "top":"-42px", "left":"15px"});
         	}
         }

      });
